import{_ as e,c as n,o as t,a}from"./app.75fe7403.js";const f=JSON.parse('{"title":"Version 2 Breaking Changes","description":"","frontmatter":{},"headers":[{"level":2,"title":"Breaking Changes","slug":"breaking-changes","link":"#breaking-changes","children":[]}],"relativePath":"v2-breaking-changes.md"}'),o={name:"v2-breaking-changes.md"},s=a(`<h1 id="version-2-breaking-changes" tabindex="-1">Version 2 Breaking Changes <a class="header-anchor" href="#version-2-breaking-changes" aria-hidden="true">#</a></h1><p>Version 2 marks a turning point for QueryFirst. We&#39;ve taken the source private. We&#39;ve got a load of new features, and some breaking changes, and we&#39;re going to start charging for a premium version. After 6 years as an open source project, the goal is to try something else to build momentum around the project. There lots we&#39;d love to do, but it depends on a revenue stream. The free version will do everything essential. New version 2 features like dynamic order-by, expando params and typescript generation will go into the premium version.</p><p><strong>TL;dr <a href="https://github.com/bbsimonbb/QueryFirstMigrate" target="_blank" rel="noreferrer">Use this</a> migration tool to convert your projects.</strong></p><h2 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-hidden="true">#</a></h2><ul><li><p>No more user partial class. The template no longer includes this file, but the generated repo and poco are still marked as partial. The namespace is no longer read from this file. The default namespace, based on folder structure, is used. If you need to override this, you can add a &quot;namespace&quot; property to the query&#39;s config.</p></li><li><p>The generated file renamed. .net core nests files based on filename, so, to enable nesting without changing settings, generated files are now called [MyQuery].sql.cs.</p></li><li><p>The generated classes renamed. QueryFirst repositories and POCOs share a distinctive structure and role, so we wanted to put their provenance right up-front in the class names.</p><ul><li>Repositories are now called [MyQuery]QfRepo. Correspondingly, the interfaces are now I[MyQuery]QfRepo.</li><li>The results class is now [MyQuery]QfDto.</li></ul><p>If you can&#39;t or don&#39;t want to make this change straight away, these suffixes are configurable (starting in v2.0.2). You just need to add the following to your qfconfig.json:</p></li></ul><div class="language-json"><button class="copy"></button><span class="lang">json</span><pre><code><span class="line"><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">repoSuffix</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">:</span><span style="color:#89DDFF;">&quot;&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">dtoSuffix</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">:</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Results</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"></span></code></pre></div><ul><li>We now use dependency injection for the connection factory. Repository instances using a static connection class was fence-sitting. Now we ask you to choose between full DI, with the connection factory injected into repositories, or full static. The static methods on the repository access the static connection factory.</li></ul><p>We have a <a href="https://www.nuget.org/api/v2/package/net.queryfirst.QueryfirstMigrate/1.0.0" target="_blank" rel="noreferrer">command-line tool</a> to help you convert your projects. Unzip the .nupkg and run the .exe, providing the name and path of the solution to convert. The migration tool is <a href="https://github.com/bbsimonbb/QueryFirstMigrate" target="_blank" rel="noreferrer">on github</a>, so you can also clone and contribute.</p>`,8),r=[s];function i(l,c,p,u,h,g){return t(),n("div",null,r)}const y=e(o,[["render",i]]);export{f as __pageData,y as default};
